1	import { Response, NextFunction } from 'express';
2	import fs from 'fs';
3	import path from 'path';
4	import { v4 as uuidv4 } from 'uuid';
5	import ExcelJS from 'exceljs';
6	import { AuthenticatedRequest } from '../middleware/auth.middleware';
7	import * as reportingService from '../services/reporting.service';
8	import { AuditLog } from '../models/audit.model';
9	import { ExportRecord } from '../models/export.model';
10	import { AppError } from '../utils/errors';
11	import { traceStore } from '../utils/logger';
12	import { objectsToCsv } from '../utils/csv';
