1	import { QueryTypes } from 'sequelize';
2	import { sequelize } from '../config/database';
3	
4	/**
5	 * Reporting service — room-night-correct KPIs
6	 *
7	 * The original implementation counted reservations rather than room
8	 * nights, which produced wrong results for any reservation that spanned
9	 * more than one night. The audit flagged this as a fundamental
10	 * correctness defect.
11	 *
12	 * Definitions used here, MySQL 8 + recursive CTE:
13	 *
14	 *   night                — a single calendar date in the [from, to]
15	 *                          inclusive range
16	 *   available_room_night — one (room, date) pair where the room is NOT
17	 *                          in `maintenance` status
18	 *   occupied_room_night  — one (room, date) pair covered by a
19	 *                          non-cancelled reservation, where the date
20	 *                          satisfies date >= check_in_date AND
21	 *                          date <  check_out_date
22	 *                          (check_in inclusive, check_out exclusive)
23	 *   revenue_cents        — sum of nightly rate_cents across the
24	 *                          occupied_room_nights set
25	 *
26	 *   Occupancy = SUM(occupied) / SUM(available)
27	 *   ADR       = SUM(revenue)  / SUM(occupied)
28	 *   RevPAR    = SUM(revenue)  / SUM(available)
29	 *
30	 * Manager scope: when a managerPropertyId is supplied (set by the
31	 * controller from req.user.propertyId), it overrides any caller-supplied
32	 * propertyId so a manager cannot peek into other properties.
33	 *
34	 * The result set is grouped by the requested rollup (day/week/month);
35	 * the underlying per-night facts are computed in a single CTE-backed
36	 * query so day/week/month all share the same source of truth.
37	 */
38	
39	interface ReportParams {
40	  propertyId?: string;
41	  from: string; // YYYY-MM-DD
42	  to: string;   // YYYY-MM-DD inclusive
43	  groupBy?: string;
44	  roomType?: string;
45	}
46	
47	const NON_CANCELLED_STATUSES = "('confirmed','checked_in','checked_out')";
48	
49	function effectivePropertyId(params: ReportParams, managerPropertyId?: string): string | undefined {
50	  return managerPropertyId || params.propertyId || undefined;
51	}
52	
53	function periodExpr(groupBy?: string): string {
54	  switch (groupBy) {
55	    case 'week':  return "DATE_FORMAT(night, '%x-W%v')";
56	    case 'month': return "DATE_FORMAT(night, '%Y-%m')";
57	    default:      return "DATE_FORMAT(night, '%Y-%m-%d')";
58	  }
59	}
60	
61	/**
62	 * Build the per-night fact CTE shared by all three KPIs. Returns the
63	 * SQL fragment plus the positional replacements that go with it.
64	 */
65	function buildPerNightCte(params: ReportParams, managerPropertyId?: string): { sql: string; replacements: unknown[] } {
66	  const propId = effectivePropertyId(params, managerPropertyId);
67	  const replacements: unknown[] = [];
68	
69	  // Anchor + recursive step uses :from and :to placeholders inlined as
70	  // positional `?`. We push the from/to twice because the available
71	  // and occupied subqueries each reference the calendar separately —
72	  // but we factor the calendar into a single CTE so we only need from/to once.
73	  replacements.push(params.from);  // calendar anchor
74	  replacements.push(params.to);    // calendar termination guard
75	
76	  // Available room-nights filter
77	  let availableWhere = "rm.status <> 'maintenance'";
78	  if (propId)         { availableWhere += ' AND rm.property_id = ?'; replacements.push(propId); }
79	  if (params.roomType){ availableWhere += ' AND rm.room_type   = ?'; replacements.push(params.roomType); }
80	
81	  // Occupied room-nights filter
82	  let occupiedWhere = `res.status IN ${NON_CANCELLED_STATUSES} AND rm.status <> 'maintenance'`;
83	  if (propId)          { occupiedWhere += ' AND rm.property_id = ?'; replacements.push(propId); }
84	  if (params.roomType) { occupiedWhere += ' AND rm.room_type   = ?'; replacements.push(params.roomType); }
85	
86	  const sql = `
87	    WITH RECURSIVE calendar (night) AS (
88	      SELECT DATE(?)
89	      UNION ALL
90	      SELECT DATE_ADD(night, INTERVAL 1 DAY)
91	      FROM calendar
92	      WHERE night < DATE(?)
93	    ),
94	    available AS (
95	      SELECT cal.night AS night, COUNT(*) AS available_rooms
96	      FROM calendar cal
97	      CROSS JOIN rooms rm
98	      WHERE ${availableWhere}
99	      GROUP BY cal.night
100	    ),
101	    occupied AS (
102	      SELECT cal.night AS night,
103	             COUNT(*) AS occupied_rooms,
104	             COALESCE(SUM(res.rate_cents), 0) AS revenue_cents
105	      FROM calendar cal
106	      JOIN reservations res
107	        ON cal.night >= res.check_in_date
108	       AND cal.night <  res.check_out_date
109	      JOIN rooms rm
110	        ON rm.id = res.room_id
111	      WHERE ${occupiedWhere}
112	      GROUP BY cal.night
113	    ),
114	    per_night AS (
115	      SELECT a.night AS night,
116	             a.available_rooms AS available_rooms,
117	             COALESCE(o.occupied_rooms, 0) AS occupied_rooms,
118	             COALESCE(o.revenue_cents, 0) AS revenue_cents
119	      FROM available a
120	      LEFT JOIN occupied o ON o.night = a.night
121	    )
122	  `;
123	
124	  return { sql, replacements };
125	}
126	
127	export async function occupancy(params: ReportParams, managerPropertyId?: string) {
128	  const cte = buildPerNightCte(params, managerPropertyId);
129	  const period = periodExpr(params.groupBy);
130	  const sql = `${cte.sql}
131	    SELECT ${period} AS period,
132	           SUM(available_rooms) AS available_room_nights,
133	           SUM(occupied_rooms)  AS occupied_room_nights,
134	           ROUND(SUM(occupied_rooms) / NULLIF(SUM(available_rooms), 0), 4) AS occupancy_rate
135	    FROM per_night
136	    GROUP BY period
137	    ORDER BY period`;
138	  return sequelize.query(sql, { replacements: cte.replacements, type: QueryTypes.SELECT });
139	}
140	
141	export async function adr(params: ReportParams, managerPropertyId?: string) {
142	  const cte = buildPerNightCte(params, managerPropertyId);
143	  const period = periodExpr(params.groupBy);
144	  const sql = `${cte.sql}
145	    SELECT ${period} AS period,
146	           SUM(revenue_cents) AS revenue_cents,
147	           SUM(occupied_rooms) AS occupied_room_nights,
148	           ROUND(SUM(revenue_cents) / NULLIF(SUM(occupied_rooms), 0), 2) AS adr_cents
149	    FROM per_night
150	    GROUP BY period
151	    ORDER BY period`;
152	  return sequelize.query(sql, { replacements: cte.replacements, type: QueryTypes.SELECT });
153	}
154	
155	export async function revpar(params: ReportParams, managerPropertyId?: string) {
156	  const cte = buildPerNightCte(params, managerPropertyId);
157	  const period = periodExpr(params.groupBy);
158	  const sql = `${cte.sql}
159	    SELECT ${period} AS period,
160	           SUM(revenue_cents) AS revenue_cents,
161	           SUM(available_rooms) AS available_room_nights,
162	           ROUND(SUM(revenue_cents) / NULLIF(SUM(available_rooms), 0), 2) AS revpar_cents
163	    FROM per_night
164	    GROUP BY period
165	    ORDER BY period`;
166	  return sequelize.query(sql, { replacements: cte.replacements, type: QueryTypes.SELECT });
167	}
168	
169	/**
170	 * Revenue mix: total revenue partitioned by either room_type or
171	 * channel. Uses the same per-night CTE so revenue numbers are
172	 * consistent with the room-night KPIs above (no double counting).
173	 */
174	export async function revenueMix(params: ReportParams, managerPropertyId?: string) {
175	  const propId = effectivePropertyId(params, managerPropertyId);
176	  const replacements: unknown[] = [];
177	  replacements.push(params.from);
178	  replacements.push(params.to);
179	
180	  let scopeWhere = `res.status IN ${NON_CANCELLED_STATUSES} AND rm.status <> 'maintenance'`;
181	  if (propId) { scopeWhere += ' AND rm.property_id = ?'; replacements.push(propId); }
182	
183	  // groupBy defines the partition column. Allow only safe values to
184	  // avoid SQL injection through `groupBy`.
185	  const groupCol = params.groupBy === 'room_type' ? 'rm.room_type' : 'res.channel';
186	
187	  const sql = `
188	    WITH RECURSIVE calendar (night) AS (
189	      SELECT DATE(?)
190	      UNION ALL
191	      SELECT DATE_ADD(night, INTERVAL 1 DAY)
192	      FROM calendar
193	      WHERE night < DATE(?)
194	    )
195	    SELECT ${groupCol} AS category,
196	           SUM(res.rate_cents) AS total_revenue,
197	           COUNT(*) AS room_nights
198	    FROM calendar cal
199	    JOIN reservations res
200	      ON cal.night >= res.check_in_date
201	     AND cal.night <  res.check_out_date
202	    JOIN rooms rm
203	      ON rm.id = res.room_id
204	    WHERE ${scopeWhere}
205	    GROUP BY category
206	    ORDER BY total_revenue DESC`;
207	
208	  return sequelize.query(sql, { replacements, type: QueryTypes.SELECT });
209	}
