1	import { Router } from 'express';
2	import * as ctrl from '../controllers/reports.controller';
3	import * as importCtrl from '../controllers/import.controller';
4	import { authMiddleware, requireRole } from '../middleware/auth.middleware';
5	import { userLimiter } from '../middleware/rate-limit.middleware';
6	import { validate, validateQuery } from '../middleware/validation.middleware';
7	import {
8	  reportQuerySchema,
9	  revenueMixQuerySchema,
10	  reportExportSchema,
11	} from '../utils/validation';
12	
13	const router = Router();
14	router.use(authMiddleware);
15	router.use(userLimiter);
16	router.use(requireRole('hotel_admin', 'manager', 'analyst'));
17	
18	// Each KPI endpoint validates from/to/groupBy/propertyId/roomType.
19	// reportQuerySchema enforces date format and from <= to.
20	router.get('/occupancy',   validateQuery(reportQuerySchema),       ctrl.occupancy);
21	router.get('/adr',         validateQuery(reportQuerySchema),       ctrl.adr);
22	router.get('/revpar',      validateQuery(reportQuerySchema),       ctrl.revpar);
23	router.get('/revenue-mix', validateQuery(revenueMixQuerySchema),   ctrl.revenueMix);
24	
25	router.post('/export', validate(reportExportSchema), ctrl.exportReport);
26	
27	router.get('/staffing', importCtrl.staffingReport);
28	router.get('/evaluations', importCtrl.evaluationReport);
29	
30	export default router;
