165	export async function updateItem(groupId: string, itemId: string, userId: string, data: {
166	  title?: string; meetupDate?: string; meetupTime?: string; meetupLocation?: string;
167	  notes?: string; idempotencyKey: string;
168	}) {
169	  await assertGroupMember(groupId, userId);
170	  validateItem(data);
171	
172	  // Update idempotency: replay stored response if same key+body
173	  const replay = await checkIdempotency(data.idempotencyKey, userId, 'update_itinerary', data);
174	  if (replay) return replay as ItineraryItem;
175	
176	  const item = await ItineraryItem.findOne({ where: { id: itemId, group_id: groupId } });
177	  if (!item) throw new AppError(404, 'NOT_FOUND', 'Itinerary item not found');
178	
179	  const t = await sequelize.transaction();
180	  try {
181	    const updateData: Record<string, unknown> = {};
182	    if (data.title) updateData.title = data.title;
183	    if (data.meetupDate) updateData.meetup_date = data.meetupDate;
184	    if (data.meetupTime) updateData.meetup_time = data.meetupTime;
185	    if (data.meetupLocation) updateData.meetup_location = data.meetupLocation;
186	    if (data.notes !== undefined) updateData.notes = data.notes;
187	    const newDate = data.meetupDate || item.meetup_date;
188	    const newTime = data.meetupTime || item.meetup_time;
189	    updateData.meetup_sort_at = parseSortDate(newDate, newTime);
190	
191	    await ItineraryItem.update(updateData, { where: { id: itemId }, transaction: t });
192	    await t.commit();
193	
194	    await emitNotification({
195	      groupId, actorId: userId, eventType: 'item_updated',
196	      resourceType: 'itinerary_item', resourceId: itemId,
197	      detail: { fields: Object.keys(updateData) }, idempotencyKey: `item_updated:${itemId}:${Date.now()}`,
198	    });
199	    const result = await ItineraryItem.findByPk(itemId);
200	    await storeIdempotency(data.idempotencyKey, userId, 'update_itinerary', itemId, data, result?.toJSON());
201	    return result;
202	  } catch (err) { await t.rollback(); throw err; }
203	}
