246	export async function updateCheckpoint(groupId: string, itemId: string, checkpointId: string, userId: string, data: { label?: string; position?: number; description?: string }) {
247	  await assertGroupMember(groupId, userId);
248	  const cp = await ItineraryCheckpoint.findOne({ where: { id: checkpointId, item_id: itemId } });
249	  if (!cp) throw new AppError(404, 'NOT_FOUND', 'Checkpoint not found');
250	  const updateData: Record<string, unknown> = {};
251	  if (data.label) updateData.label = data.label;
252	  if (data.description !== undefined) updateData.description = data.description;
253	  if (data.position !== undefined) {
254	    // Check position conflict
255	    const conflict = await ItineraryCheckpoint.findOne({ where: { item_id: itemId, position: data.position } });
256	    if (conflict && conflict.id !== checkpointId) throw new AppError(409, 'CONFLICT', `Position ${data.position} already occupied`);
257	    updateData.position = data.position;
258	  }
259	  await ItineraryCheckpoint.update(updateData, { where: { id: checkpointId } });
260	  return ItineraryCheckpoint.findByPk(checkpointId);
261	}
