270	// --- Check-in ---
271	export async function checkin(groupId: string, itemId: string, userId: string) {
272	  await assertGroupMember(groupId, userId);
273	  const item = await ItineraryItem.findOne({ where: { id: itemId, group_id: groupId } });
274	  if (!item) throw new AppError(404, 'NOT_FOUND', 'Itinerary item not found');
275	
276	  // Check required fields
277	  const requiredFields = await GroupRequiredField.findAll({ where: { group_id: groupId, is_required: true } });
278	  if (requiredFields.length > 0) {
279	    const values = await MemberFieldValue.findAll({ where: { group_id: groupId, user_id: userId } });
280	    const valueMap = new Map(values.map(v => [v.field_name, v.value]));
281	    const missing = requiredFields.filter(f => !valueMap.has(f.field_name) || !valueMap.get(f.field_name)).map(f => f.field_name);
282	    if (missing.length > 0)
283	      throw new AppError(400, 'MISSING_REQUIRED_FIELDS', `Missing required fields: ${missing.join(', ')}`);
284	  }
285	
286	  const existing = await MemberCheckin.findOne({ where: { item_id: itemId, user_id: userId } });
287	  if (existing) return existing;
288	
289	  return MemberCheckin.create({ id: uuidv4(), item_id: itemId, user_id: userId, checked_in_at: new Date() });
290	}
