51	export async function updateUser(req: AuthenticatedRequest, res: Response, next: NextFunction): Promise<void> {
52	  try {
53	    const user = await User.findByPk(req.params.id, { paranoid: false });
54	    if (!user) {
55	      throw new AppError(ErrorCodes.NOT_FOUND.statusCode, ErrorCodes.NOT_FOUND.code, 'User not found');
56	    }
57	
58	    const allowedFields: Record<string, string> = {
59	      role: 'role',
60	      status: 'status',
61	      propertyId: 'property_id',
62	      piiExportAllowed: 'pii_export_allowed',
63	    };
64	
65	    const data: Record<string, unknown> = {};
66	    for (const [camel, snake] of Object.entries(allowedFields)) {
67	      if (req.body[camel] !== undefined) {
68	        data[snake] = req.body[camel];
69	      }
70	    }
71	
72	    // If status changes to 'deleted', set deleted_at
73	    if (data.status === 'deleted' && user.status !== 'deleted') {
74	      data.deleted_at = new Date();
75	    }
76	    // If status changes from 'deleted' to something else, clear deleted_at
77	    if (data.status && data.status !== 'deleted' && user.status === 'deleted') {
78	      data.deleted_at = null;
79	    }
80	
81	    await User.update(data, { where: { id: req.params.id }, paranoid: false });
82	
83	    const updated = await User.findByPk(req.params.id, {
84	      attributes: { exclude: ['password_hash'] },
85	      paranoid: false,
86	    });
87	
88	    res.status(200).json(updated);
89	  } catch (err) {
90	    next(err);
91	  }
92	}
93	
94	export async function deleteUser(req: AuthenticatedRequest, res: Response, next: NextFunction): Promise<void> {
95	  try {
96	    const user = await User.findByPk(req.params.id);
97	    if (!user) {
98	      throw new AppError(ErrorCodes.NOT_FOUND.statusCode, ErrorCodes.NOT_FOUND.code, 'User not found');
99	    }
100	
101	    // Prevent self-deletion via admin route
102	    if (user.id === req.user!.id) {
103	      throw new AppError(ErrorCodes.CONFLICT.statusCode, ErrorCodes.CONFLICT.code, 'Cannot delete your own account via this endpoint');
104	    }
105	
106	    await User.update(
107	      { status: 'deleted', deleted_at: new Date() },
108	      { where: { id: req.params.id } }
109	    );
110	
111	    res.status(204).send();
112	  } catch (err) {
113	    next(err);
114	  }
115	}
