235	export async function deleteAccount(userId: string, password: string): Promise<void> {
236	  const user = await User.findByPk(userId);
237	  if (!user) {
238	    throw new AppError(ErrorCodes.NOT_FOUND.statusCode, ErrorCodes.NOT_FOUND.code, 'User not found');
239	  }
240	
241	  const valid = await bcrypt.compare(password, user.password_hash);
242	  if (!valid) {
243	    throw new AppError(ErrorCodes.UNAUTHORIZED.statusCode, ErrorCodes.UNAUTHORIZED.code, 'Invalid password');
244	  }
245	
246	  // Deactivate face enrollments
247	  await FaceEnrollment.update({ status: 'deactivated' }, { where: { user_id: userId, status: 'active' } });
248	
249	  // Transfer owned groups or archive them
250	  const ownedGroups = await GroupMember.findAll({ where: { user_id: userId, role: 'owner' } });
251	  for (const membership of ownedGroups) {
252	    const nextAdmin = await GroupMember.findOne({
253	      where: { group_id: membership.group_id, role: 'admin', user_id: { [require('sequelize').Op.ne]: userId } },
254	    });
255	    if (nextAdmin) {
256	      await GroupMember.update({ role: 'owner' }, { where: { id: nextAdmin.id } });
257	      // Keep groups.owner_id consistent with the new owner
258	      await Group.update({ owner_id: nextAdmin.user_id }, { where: { id: membership.group_id } });
259	    } else {
260	      await Group.update({ status: 'archived' }, { where: { id: membership.group_id } });
261	    }
262	  }
263	
264	  // Remove all group memberships
265	  await GroupMember.destroy({ where: { user_id: userId } });
266	
267	  // Soft-delete user
268	  await User.update(
269	    { status: 'deleted', deleted_at: new Date() },
270	    { where: { id: userId } }
271	  );
272	
273	  await logActivity(userId, 'delete_account');
274	  await logAudit(userId, 'delete_account', 'user', userId, {
275	    cascaded: { faceEnrollmentsDeactivated: true, groupMembershipsRemoved: true, ownedGroupsHandled: ownedGroups.length },
276	  });
277	  authLogger.info('Account deleted with cascade', { userId });
278	}
