67	export async function exportReport(req: AuthenticatedRequest, res: Response, next: NextFunction): Promise<void> {
68	  try {
69	    const scope = getManagerScope(req);
70	    const { reportType, from, to, format, groupBy, propertyId, roomType, includePii } = req.body;
71	
72	    if (includePii) {
73	      const { User } = require('../models/user.model');
74	      const user = await User.findByPk(req.user!.id);
75	      if (!user?.pii_export_allowed) throw new AppError(403, 'FORBIDDEN', 'PII export not permitted');
76	    }
77	
78	    // `roomType` is intentionally forwarded only to the room-night KPIs
79	    // (occupancy/adr/revpar). `revenue_mix` already partitions by
80	    // `rm.room_type` when `groupBy=room_type`, so layering a roomType
81	    // filter on top would collapse the partition — preserve existing
82	    // behavior there.
83	    let data: unknown[];
84	    switch (reportType) {
85	      case 'occupancy': data = await reportingService.occupancy({ propertyId, from, to, groupBy, roomType }, scope); break;
86	      case 'adr': data = await reportingService.adr({ propertyId, from, to, groupBy, roomType }, scope); break;
87	      case 'revpar': data = await reportingService.revpar({ propertyId, from, to, groupBy, roomType }, scope); break;
88	      case 'revenue_mix': data = await reportingService.revenueMix({ propertyId, from, to, groupBy }, scope); break;
89	      default: throw new AppError(400, 'VALIDATION_ERROR', 'Invalid reportType');
90	    }
91	
92	    const exportId = uuidv4();
93	    const rows = data as Record<string, unknown>[];
94	    let filename: string;
95	    let filePath: string;
96	
97	    if (format === 'excel') {
98	      filename = `report-${reportType}-${exportId}.xlsx`;
99	      filePath = path.resolve('exports', filename);
100	      const wb = new ExcelJS.Workbook();
101	      const ws = wb.addWorksheet(reportType);
102	      if (rows.length > 0) {
103	        ws.addRow(Object.keys(rows[0]));
104	        for (const row of rows) ws.addRow(Object.values(row));
105	      }
106	      await wb.xlsx.writeFile(filePath);
107	    } else {
108	      // CSV — serialized via serializeReportRowsToCsv → objectsToCsv so
109	      // every cell is properly quoted (commas / newlines / embedded
110	      // quotes) and values that begin with formula-trigger characters
111	      // (=, +, -, @) are neutralized against spreadsheet formula
112	      // injection. See src/utils/csv.ts.
113	      filename = `report-${reportType}-${exportId}.csv`;
114	      filePath = path.resolve('exports', filename);
115	      fs.writeFileSync(filePath, serializeReportRowsToCsv(rows));
116	    }
117	
118	    // Log export metadata to audit_logs
119	    await AuditLog.create({
120	      id: uuidv4(),
121	      actor_id: req.user!.id,
122	      action: 'report_export',
123	      resource_type: 'report',
124	      resource_id: exportId,
125	      detail: { reportType, from, to, format, groupBy, propertyId, roomType, includePii: !!includePii, rowCount: rows.length },
126	      trace_id: traceStore.getStore()?.traceId || null,
127	      ip_address: req.ip || null,
128	      created_at: new Date(),
129	    });
130	
131	    // Register export ownership
132	    await ExportRecord.create({
133	      id: exportId, user_id: req.user!.id, filename,
134	      export_type: 'report',
135	      expires_at: new Date(Date.now() + 24 * 60 * 60 * 1000),
136	      created_at: new Date(),
